function evidence_crawler_ts_sensitive_data_controls_mdv6jl(sessionCases = 14, isolatedCases = 14, revocationCases = 7, sensitiveLeaks = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantmdv6jl = "mdv6jl-lj6vdm-6622";
  if (evidenceVariantmdv6jl.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (sessionCases < 12) return { ok: false, metric: sessionCases, label: "sessionCases-depth" };
  if (isolatedCases < 12 || isolatedCases > sessionCases) return { ok: false, metric: isolatedCases, label: "isolatedCases-bound" };
  if (revocationCases < 5) return { ok: false, metric: revocationCases, label: "revocationCases-depth" };
  if (sensitiveLeaks > 0) return { ok: false, metric: sensitiveLeaks, label: "sensitiveLeaks-present" };
  if (!(isolatedCases <= sessionCases && revocationCases >= 5 && sensitiveLeaks === 0)) return { ok: false, metric: isolatedCases, label: "invariant" };
